import React, { useState } from 'react';
import axios from 'axios';
import { Search, Popcorn } from 'lucide-react';
import MovieCard from './components/MovieCard';
import MovieDetails from './components/MovieDetails';
import './index.css';

function App() {
  const [movie, setMovie] = useState('');
  const [primaryMovie, setPrimaryMovie] = useState(null);
  const [recommendations, setRecommendations] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Pagination / Load More state
  const [visibleCount, setVisibleCount] = useState(20);

  const fetchRecommendations = async (e) => {
    e.preventDefault();
    if (!movie.trim()) return;

    setLoading(true);
    setError('');
    setPrimaryMovie(null);
    setRecommendations([]);
    setVisibleCount(20);

    try {
      // Send get_1000 flag to tell backend to give us a massive list
      const response = await axios.post('http://localhost:5000/recommend', {
        movie: movie,
        get_1000: true
      });

      setPrimaryMovie(response.data.primary);
      setRecommendations(response.data.recommendations || []);
    } catch (err) {
      console.error(err);
      if (err.response && err.response.status === 404) {
        setError("Movie not found. Please try another one!");
      } else {
        setError('Failed to fetch recommendations. Is the backend running?');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleSearchClick = (e) => {
      fetchRecommendations(e);
  };

  const handleLoadMore = () => {
      setVisibleCount(prev => prev + 20);
  };

  return (
    <div className="app-container">
      {!primaryMovie && (
        <header className="header">
          <h1>AniMovie Explorer</h1>
          <p>Discover endless movies recommended by AI</p>
        </header>
      )}

      <main className={`search-section ${primaryMovie ? 'search-top' : ''}`}>
        <form onSubmit={fetchRecommendations} className="search-box">
          <input
            type="text"
            className="search-input"
            value={movie}
            onChange={(e) => setMovie(e.target.value)}
            placeholder="Search for a movie..."
          />
          <button type="submit" className="search-btn" disabled={loading}>
            {loading ? (
              <div className="spinner" style={{ width: '20px', height: '20px', borderWidth: '2px' }}></div>
            ) : (
              <>
                <Search size={20} />
                <span className="search-text-hide">Search</span>
              </>
            )}
          </button>
        </form>
        {error && <div className="error-message">{error}</div>}
      </main>

      {primaryMovie && (
        <>
          <MovieDetails data={primaryMovie} />

          <div className="recommendations-container">
            <h2 className="recommendations-title">Recommended Just For You</h2>
            <div className="results-grid">
              {recommendations.slice(0, visibleCount).map((rec, index) => (
                <MovieCard key={index} movie={rec} delay={(index % 20) * 0.05} />
              ))}
            </div>

            {visibleCount < recommendations.length && (
                <div className="load-more-container">
                   <button onClick={handleLoadMore} className="load-more-btn">
                       Load More ({recommendations.length - visibleCount} available)
                   </button>
                </div>
            )}
          </div>
        </>
      )}
    </div>
  );
}

export default App;
